1	import type { Shape } from "./types.ts";
2	
3	export interface CursorInfo {
4	  x: number;
5	  y: number;
6	  username: string;
7	  color: string;
8	  opacity?: number;
9	}
10	
11	export interface SelectionState {
12	  shapeId: string;
13	  handles: { x: number; y: number; w: number; h: number }[];
14	}
15	
16	const HANDLE_SIZE = 8;
17	
18	export function renderScene(
19	  ctx: CanvasRenderingContext2D,
20	  shapes: Shape[],
21	  selection: SelectionState | null,
22	  cursors: Map<string, CursorInfo>,
23	  previewShape: Shape | null,
24	  canvasWidth: number,
25	  canvasHeight: number,
26	  dpr: number
27	): void {
28	  ctx.save();
29	  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
30	
31	  // Background
32	  ctx.fillStyle = "#f8f9fb";
33	  ctx.fillRect(0, 0, canvasWidth, canvasHeight);
34	
35	  // Dot grid
36	  ctx.fillStyle = "#d4d5db";
37	  const gridSpacing = 20;
38	  const dotSize = 1;
39	  for (let gx = gridSpacing; gx < canvasWidth; gx += gridSpacing) {
40	    for (let gy = gridSpacing; gy < canvasHeight; gy += gridSpacing) {
41	      ctx.fillRect(gx - dotSize / 2, gy - dotSize / 2, dotSize, dotSize);
42	    }
43	  }
44	
45	  // Draw shapes with selected shape rendered last (on top) for visual "lift"
46	  const selectedShapeId = selection?.shapeId ?? null;
47	  let selectedShape: Shape | null = null;
48	
49	  for (const shape of shapes) {
50	    if (shape.id === selectedShapeId) {
51	      selectedShape = shape;
52	      continue; // skip — will draw last
53	    }
54	    drawShape(ctx, shape);
55	  }
56	
57	  // Draw selected shape on top of all others
58	  if (selectedShape) {
59	    drawShape(ctx, selectedShape);
60	  }
61	
62	  // Draw preview shape
63	  if (previewShape) {
64	    drawShape(ctx, previewShape);
65	  }
66	
67	  // Draw selection box over the (already-drawn) selected shape
68	  if (selection && selectedShape) {
69	    drawSelectionBox(ctx, selectedShape);
70	  }
71	
72	  // Draw remote cursors
73	  for (const [, cursor] of cursors) {
74	    drawCursor(ctx, cursor);
75	  }
76	
77	  ctx.restore();
78	}
79	
80	function drawShape(ctx: CanvasRenderingContext2D, shape: Shape): void {
81	  ctx.save();
82	  ctx.globalAlpha = (shape as any).opacity ?? 1;
83	  ctx.fillStyle = shape.fill || "transparent";
84	  ctx.strokeStyle = shape.stroke || "#000000";
85	  ctx.lineWidth = shape.strokeWidth;
86	
87	  switch (shape.type) {
88	    case "rectangle": {
89	      const br = (shape as any).borderRadius || 0;
90	      if (br > 0) {
91	        ctx.beginPath();
92	        ctx.roundRect(shape.x, shape.y, shape.width, shape.height, br);
93	        if (shape.fill) ctx.fill();
94	        ctx.stroke();
95	      } else {
96	        if (shape.fill) ctx.fillRect(shape.x, shape.y, shape.width, shape.height);
97	        ctx.strokeRect(shape.x, shape.y, shape.width, shape.height);
98	      }
99	      break;
100	    }
101	
102	    case "ellipse": {
103	      const cx = shape.x + shape.width / 2;
104	      const cy = shape.y + shape.height / 2;
105	      const rx = Math.abs(shape.width / 2);
106	      const ry = Math.abs(shape.height / 2);
107	      ctx.beginPath();
108	      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
109	      if (shape.fill) {
110	        ctx.fill();
111	      }
112	      ctx.stroke();
113	      break;
114	    }
115	
116	    case "line":
117	      ctx.beginPath();
118	      ctx.moveTo(shape.x, shape.y);
119	      ctx.lineTo(shape.x + shape.width, shape.y + shape.height);
120	      ctx.stroke();
121	      break;
122	
123	    case "text": {
124	      const fontSize = shape.fontSize || 16;
125	      ctx.font = `${fontSize}px sans-serif`;
126	      const measured = ctx.measureText(shape.text || "");
127	      // Update stored width to match actual rendered width for hit-testing
128	      shape.width = measured.width;
129	      shape.height = fontSize * 1.2; // line height
130	      ctx.fillStyle = shape.fill || "#000000";
131	      ctx.fillText(shape.text || "", shape.x, shape.y + fontSize);
132	      if (shape.stroke && shape.strokeWidth > 0) {
133	        ctx.strokeStyle = shape.stroke;
134	        ctx.lineWidth = shape.strokeWidth;
135	        ctx.strokeText(shape.text || "", shape.x, shape.y + fontSize);
136	      }
137	      break;
138	    }
139	  }
140	
141	  ctx.restore();
142	}
