144	function drawSelectionBox(ctx: CanvasRenderingContext2D, shape: Shape): void {
145	  ctx.save();
146	  ctx.strokeStyle = "#0088ff";
147	  ctx.lineWidth = 1;
148	  ctx.setLineDash([4, 4]);
149	  ctx.strokeRect(shape.x - 2, shape.y - 2, shape.width + 4, shape.height + 4);
150	  ctx.setLineDash([]);
151	
152	  // Draw handles at corners
153	  const handles = getHandlePositions(shape);
154	  ctx.fillStyle = "#0088ff";
155	  for (const h of handles) {
156	    ctx.fillRect(h.x, h.y, h.w, h.h);
157	  }
158	
159	  ctx.restore();
160	}
161	
162	export function getHandlePositions(
163	  shape: Shape
164	): { x: number; y: number; w: number; h: number; corner: string }[] {
165	  const hs = HANDLE_SIZE;
166	  const half = hs / 2;
167	  return [
168	    { x: shape.x - half - 2, y: shape.y - half - 2, w: hs, h: hs, corner: "nw" },
169	    { x: shape.x + shape.width - half + 2, y: shape.y - half - 2, w: hs, h: hs, corner: "ne" },
170	    { x: shape.x - half - 2, y: shape.y + shape.height - half + 2, w: hs, h: hs, corner: "sw" },
171	    {
172	      x: shape.x + shape.width - half + 2,
173	      y: shape.y + shape.height - half + 2,
174	      w: hs,
175	      h: hs,
176	      corner: "se",
177	    },
178	  ];
179	}
180	
181	function drawCursor(ctx: CanvasRenderingContext2D, cursor: CursorInfo): void {
182	  ctx.save();
183	  ctx.globalAlpha = cursor.opacity ?? 1;
184	
185	  // Draw cursor arrow
186	  ctx.fillStyle = cursor.color;
187	  ctx.strokeStyle = "#ffffff";
188	  ctx.lineWidth = 1;
189	
190	  ctx.beginPath();
191	  ctx.moveTo(cursor.x, cursor.y);
192	  ctx.lineTo(cursor.x, cursor.y + 16);
193	  ctx.lineTo(cursor.x + 5, cursor.y + 12);
194	  ctx.lineTo(cursor.x + 10, cursor.y + 12);
195	  ctx.closePath();
196	  ctx.fill();
197	  ctx.stroke();
198	
199	  // Draw username label
200	  ctx.font = "11px sans-serif";
201	  const metrics = ctx.measureText(cursor.username);
202	  const labelX = cursor.x + 12;
203	  const labelY = cursor.y + 10;
204	  const padding = 3;
205	
206	  ctx.fillStyle = cursor.color;
207	  const rx = labelX - padding;
208	  const ry2 = labelY - 10 - padding;
209	  const rw = metrics.width + padding * 2;
210	  const rh = 14 + padding * 2;
211	  const r = 3;
212	  ctx.beginPath();
213	  ctx.moveTo(rx + r, ry2);
214	  ctx.lineTo(rx + rw - r, ry2);
215	  ctx.arcTo(rx + rw, ry2, rx + rw, ry2 + r, r);
216	  ctx.lineTo(rx + rw, ry2 + rh - r);
217	  ctx.arcTo(rx + rw, ry2 + rh, rx + rw - r, ry2 + rh, r);
218	  ctx.lineTo(rx + r, ry2 + rh);
219	  ctx.arcTo(rx, ry2 + rh, rx, ry2 + rh - r, r);
220	  ctx.lineTo(rx, ry2 + r);
221	  ctx.arcTo(rx, ry2, rx + r, ry2, r);
222	  ctx.closePath();
223	  ctx.fill();
224	
225	  ctx.fillStyle = "#ffffff";
226	  ctx.fillText(cursor.username, labelX, labelY);
227	
228	  ctx.restore();
229	}
