231	export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
232	  // Iterate in reverse z-order (topmost first)
233	  for (let i = shapes.length - 1; i >= 0; i--) {
234	    const s = shapes[i];
235	    if (isPointInShape(s, x, y)) {
236	      return s;
237	    }
238	  }
239	  return null;
240	}
241	
242	function isPointInShape(shape: Shape, px: number, py: number): boolean {
243	  const margin = 4;
244	  switch (shape.type) {
245	    case "rectangle":
246	    case "text":
247	      return (
248	        px >= shape.x - margin &&
249	        px <= shape.x + shape.width + margin &&
250	        py >= shape.y - margin &&
251	        py <= shape.y + shape.height + margin
252	      );
253	
254	    case "ellipse": {
255	      const cx = shape.x + shape.width / 2;
256	      const cy = shape.y + shape.height / 2;
257	      const rx = Math.abs(shape.width / 2) + margin;
258	      const ry = Math.abs(shape.height / 2) + margin;
259	      if (rx === 0 || ry === 0) return false;
260	      const dx = px - cx;
261	      const dy = py - cy;
262	      return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
263	    }
264	
265	    case "line": {
266	      // Check distance from point to line segment
267	      const x1 = shape.x;
268	      const y1 = shape.y;
269	      const x2 = shape.x + shape.width;
270	      const y2 = shape.y + shape.height;
271	      const dist = distToSegment(px, py, x1, y1, x2, y2);
272	      return dist <= shape.strokeWidth / 2 + margin + 4;
273	    }
274	
275	    default:
276	      return false;
277	  }
278	}
279	
280	function distToSegment(
281	  px: number,
282	  py: number,
283	  x1: number,
284	  y1: number,
285	  x2: number,
286	  y2: number
287	): number {
288	  const dx = x2 - x1;
289	  const dy = y2 - y1;
290	  const lenSq = dx * dx + dy * dy;
291	  if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
292	  let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
293	  t = Math.max(0, Math.min(1, t));
294	  const projX = x1 + t * dx;
295	  const projY = y1 + t * dy;
296	  return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
297	}
298	
299	export function hitTestHandle(
300	  shape: Shape,
301	  x: number,
302	  y: number
303	): string | null {
304	  const handles = getHandlePositions(shape);
305	  for (const h of handles) {
306	    if (x >= h.x && x <= h.x + h.w && y >= h.y && y <= h.y + h.h) {
307	      return h.corner;
308	    }
309	  }
310	  return null;
311	}
