1	import { useState, useEffect } from "react";
2	import type { CanvasSummary } from "../types.ts";
3	import { getCanvases, createCanvas, deleteCanvas, ApiError } from "../api.ts";
4	import { clearAuth, getStoredUser } from "../authStore.ts";
5	
6	interface CanvasListProps {
7	  onSelectCanvas: (canvasId: string) => void;
8	  onLogout: () => void;
9	}
10	
11	export default function CanvasList({
12	  onSelectCanvas,
13	  onLogout,
14	}: CanvasListProps) {
15	  const [canvases, setCanvases] = useState<CanvasSummary[]>([]);
16	  const [newName, setNewName] = useState("");
17	  const [loading, setLoading] = useState(true);
18	  const [error, setError] = useState("");
19	  const [creating, setCreating] = useState(false);
20	  const user = getStoredUser();
21	
22	  useEffect(() => {
23	    let cancelled = false;
24	    getCanvases()
25	      .then((data) => {
26	        if (!cancelled) {
27	          setCanvases(data);
28	          setLoading(false);
29	        }
30	      })
31	      .catch((err) => {
32	        if (!cancelled) {
33	          if (err instanceof ApiError && err.status === 401) {
34	            handleLogout();
35	          } else {
36	            setError("Failed to load canvases.");
37	            setLoading(false);
38	          }
39	        }
40	      });
41	    return () => { cancelled = true; };
42	    // eslint-disable-next-line react-hooks/exhaustive-deps
43	  }, []);
44	
45	  const handleLogout = () => {
46	    clearAuth();
47	    onLogout();
48	  };
49	
50	  const handleCreate = async (e: React.FormEvent) => {
51	    e.preventDefault();
52	    if (!newName.trim()) return;
53	    setCreating(true);
54	    setError("");
55	    try {
56	      const canvas = await createCanvas({ name: newName.trim() });
57	      setCanvases((prev) => [canvas, ...prev]);
58	      setNewName("");
59	    } catch (err) {
60	      if (err instanceof ApiError && err.status === 401) {
61	        handleLogout();
62	      } else {
63	        setError("Failed to create canvas.");
64	      }
65	    } finally {
66	      setCreating(false);
67	    }
68	  };
69	
70	  const handleDelete = async (canvasId: string, e: React.MouseEvent) => {
71	    e.stopPropagation();
72	    if (!confirm("Delete this canvas?")) return;
73	    try {
74	      await deleteCanvas(canvasId);
75	      setCanvases((prev) => prev.filter((c) => c.id !== canvasId));
76	    } catch (err) {
77	      if (err instanceof ApiError && err.status === 401) {
78	        handleLogout();
79	      } else if (err instanceof ApiError && err.status === 403) {
80	        setError("Only the canvas owner can delete it.");
81	      } else {
82	        setError("Failed to delete canvas.");
83	      }
84	    }
85	  };
86	
87	  return (
88	    <div style={s.page}>
89	      <div style={s.container}>
90	        {/* Header */}
91	        <div style={s.header}>
92	          <div>
93	            <h1 style={s.title}>Your Canvases</h1>
94	            <p style={s.subtitle}>
95	              {user?.username ? `Signed in as ${user.username}` : ""}
96	            </p>
97	          </div>
98	          <button style={s.logoutBtn} onClick={handleLogout}>
99	            Sign out
100	          </button>
101	        </div>
102	
103	        {/* Create form */}
104	        <form onSubmit={handleCreate} style={s.createForm}>
105	          <input
106	            style={s.input}
107	            type="text"
108	            placeholder="New canvas name..."
109	            value={newName}
110	            onChange={(e) => setNewName(e.target.value)}
111	            required
112	          />
113	          <button type="submit" style={s.createBtn} disabled={creating}>
114	            {creating ? "..." : "Create"}
115	          </button>
116	        </form>
117	
118	        {error && <div style={s.error}>{error}</div>}
119	
120	        {/* Canvas grid */}
121	        {loading ? (
122	          <p style={s.empty}>Loading...</p>
123	        ) : canvases.length === 0 ? (
124	          <div style={s.emptyState}>
125	            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#c5c6d0" strokeWidth="1.5" strokeLinecap="round">
126	              <rect x="3" y="3" width="18" height="18" rx="3" />
127	              <path d="M8 12h8M12 8v8" />
128	            </svg>
129	            <p style={s.emptyText}>No canvases yet. Create one above.</p>
130	          </div>
131	        ) : (
132	          <div style={s.grid}>
133	            {canvases.map((c) => (
134	              <button
135	                key={c.id}
136	                style={s.card}
137	                onClick={() => onSelectCanvas(c.id)}
138	                onMouseEnter={(e) => {
139	                  const el = e.currentTarget as HTMLElement;
140	                  el.style.borderColor = "#5b5bff";
141	                  el.style.transform = "translateY(-2px)";
142	                  const delBtn = el.querySelector("[data-delete-btn]") as HTMLElement | null;
143	                  if (delBtn) delBtn.style.opacity = "1";
144	                }}
145	                onMouseLeave={(e) => {
146	                  const el = e.currentTarget as HTMLElement;
147	                  el.style.borderColor = "#e4e5eb";
148	                  el.style.transform = "none";
149	                  const delBtn = el.querySelector("[data-delete-btn]") as HTMLElement | null;
150	                  if (delBtn) delBtn.style.opacity = "0";
151	                }}
152	              >
153	                <div style={s.cardPreview}>
154	                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#b0b3c4" strokeWidth="1.5" strokeLinecap="round">
155	                    <rect x="4" y="4" width="7" height="7" rx="1" />
156	                    <circle cx="17" cy="7" r="3" />
157	                    <path d="M4 17l5 3 5-3 6 3" />
158	                  </svg>
159	                  <span
160	                    data-delete-btn
161	                    role="button"
162	                    title="Delete canvas"
163	                    style={s.deleteBtn}
164	                    onClick={(e) => handleDelete(c.id, e)}
165	                    onMouseEnter={(e) => {
166	                      (e.currentTarget as HTMLElement).style.background = "#e03131";
167	                      (e.currentTarget as HTMLElement).style.color = "#fff";
168	                    }}
169	                    onMouseLeave={(e) => {
170	                      (e.currentTarget as HTMLElement).style.background = "rgba(0,0,0,0.06)";
171	                      (e.currentTarget as HTMLElement).style.color = "#8b8fa3";
172	                    }}
173	                  >
174	                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
175	                      <path d="M18 6L6 18M6 6l12 12" />
176	                    </svg>
177	                  </span>
178	                </div>
179	                <div style={s.cardBody}>
180	                  <span style={s.cardName}>{c.name}</span>
181	                  <span style={s.cardDate}>
182	                    {new Date(c.createdAt).toLocaleDateString(undefined, {
183	                      month: "short",
184	                      day: "numeric",
185	                    })}
186	                  </span>
187	                </div>
188	              </button>
189	            ))}
190	          </div>
191	        )}
192	      </div>
193	    </div>
194	  );
195	}
